inline void ChkMin(int &a, int b) { if(a > b) a = b; }

inline void addEdge(int u, int v, int w) { e[++cnt] = (Edge){u, v, w}; }

int find(int x) { return fa[x] == x ? x : fa[x] = find(fa[x]); }

bool unionn(int x, int y) {

	int fx = find(x), fy = find(y);

	if(fx == fy) return 0;

	fa[fx] = fy; return 1;

}



