	for(int i = 0; i <= n; ++i) addEdge(i, (i + 1) % n, d[i]);

	sort(e + 1, e + cnt + 1);

	for(int i = 1; i < n; ++i) fa[i] = i;

	int blo = n; ll ans = 0;

	for(int i = 1; i <= cnt && blo > 1; ++i)

